from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import secrets
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    reset_token = db.Column(db.String(36))

@app.route('/api/password-reset', methods=['POST'])
def password_reset():
    data = request.get_json()
    email = data.get('email')
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({'error': 'User not found'}), 404

    user.reset_token = secrets.token_urlsafe(36)
    db.session.commit()

    # Here you should implement the email sending functionality using a library like Flask-Mail or smtplib
    reset_link = f"http://{request.host}/api/password-reset/{user.reset_token}"

    return jsonify({'message': 'Password reset link sent to your email'}), 200

@app.route('/api/password-reset/<token>', methods=['PUT'])
def password_reset_confirm(token):
    user = User.query.filter_by(reset_token=token).first()
    if not user:
        return jsonify({'error': 'Invalid or expired token'}), 400

    # Here you should implement the password updating functionality

    db.session.delete(user)
    db.session.commit()

    return jsonify({'message': 'Password updated successfully'}), 200

if __name__ == "__main__":
    app.run(debug=True)